import React from "react";
import { ArrowUpRight, ArrowDownLeft } from "lucide-react";
import { formatCurrency } from "../helpers/helpers";

export default function HomeScreen({
  balance,
  savingsBalance,
  transactions = [],
  userName,
  openScreen,
  darkMode,
  setDarkMode,
}) {
  return (
    <div className="px-6 pb-24 min-h-screen bg-gray-50 dark:bg-gray-900 animate-fade-in">
      {/* Greeting + Dark Mode Toggle */}
      <div className="flex items-center mb-6">
        <h1 className="text-2xl font-bold text-gray-900 dark:text-white">
          Hello, {userName} 👋
        </h1>
        <button
          onClick={() => setDarkMode(!darkMode)}
          className="ml-auto text-sm text-gray-400 dark:text-gray-200"
        >
          {darkMode ? "☀️" : "🌙"}
        </button>
      </div>

      {/* Total Balance Card */}
      <div className="bg-gradient-to-br from-emerald-600 to-teal-800 rounded-3xl p-6 text-white shadow-lg shadow-emerald-200 mb-8">
        <div className="flex justify-between items-start mb-2">
          <span className="text-emerald-100 text-sm font-medium">
            Total Balance
          </span>
          <span className="text-lg font-bold">Nest.</span>
        </div>
        <div className="text-4xl font-bold mb-4 tracking-tight">
          ${formatCurrency(balance)}
        </div>

        {/* Savings Balance */}
        <p className="text-emerald-200 font-medium mb-4">
          Savings: ${formatCurrency(savingsBalance)}
        </p>

        {/* Buttons */}
        <div className="flex gap-3">
          <button
            onClick={() => openScreen("Deposit")}
            className="flex-1 bg-white/20 dark:bg-gray-800/30 backdrop-blur-sm py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium hover:bg-white/30 dark:hover:bg-gray-700/40 transition-colors"
          >
            <ArrowUpRight className="w-4 h-4" /> Deposit
          </button>

          <button
            onClick={() => openScreen("Withdraw")}
            className="flex-1 bg-white/20 dark:bg-gray-800/30 backdrop-blur-sm py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium hover:bg-white/30 dark:hover:bg-gray-700/40 transition-colors"
          >
            <ArrowDownLeft className="w-4 h-4" /> Withdraw
          </button>
        </div>

        {/* Savings actions */}
        <div className="flex gap-3 mt-3">
          <button
            onClick={() => openScreen("SavingsDeposit")}
            className="flex-1 bg-emerald-500/20 dark:bg-emerald-500/30 backdrop-blur-sm py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium hover:bg-emerald-500/30 dark:hover:bg-emerald-600/40 transition-colors"
          >
            Save
          </button>

          <button
            onClick={() => openScreen("SavingsWithdraw")}
            className="flex-1 bg-emerald-500/20 dark:bg-red-500/20 backdrop-blur-sm py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium hover:bg-red-500/30 dark:hover:bg-red-600/40 transition-colors"
          >
            Withdraw Savings
          </button>
        </div>
      </div>

      {/* Recent Transactions */}
      <div>
        <div className="flex justify-between items-center mb-4">
          <h2 className="font-bold text-lg text-gray-800 dark:text-gray-100">
            Recent Transactions
          </h2>
          <button
            onClick={() => openScreen("Transactions")}
            className="text-gray-400 dark:text-gray-300"
          >
            ▶
          </button>
        </div>

        <div className="space-y-4">
          {transactions.slice(0, 5).map((t) => {
            const isDeposit = t.type.includes("deposit");
            return (
              <div
                key={t.id}
                className="flex items-center justify-between bg-white dark:bg-gray-800 p-3 rounded-xl border border-gray-50 dark:border-gray-700 cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                onClick={() => openScreen("TransactionReceipt", t)}
              >
                <div className="flex items-center gap-3">
                  <div
                    className={`w-10 h-10 rounded-full flex items-center justify-center ${
                      isDeposit
                        ? "bg-emerald-100 text-emerald-600"
                        : "bg-red-100 text-red-600"
                    }`}
                  >
                    {isDeposit ? (
                      <ArrowDownLeft className="w-5 h-5" />
                    ) : (
                      <ArrowUpRight className="w-5 h-5" />
                    )}
                  </div>
                  <div>
                    <p className="font-semibold text-gray-800 dark:text-gray-100">
                      {t.title}
                    </p>
                    <p className="text-xs text-gray-400 dark:text-gray-300">
                      {t.date}
                    </p>
                  </div>
                </div>
                <span
                  className={`font-bold text-sm ${
                    isDeposit ? "text-emerald-600" : "text-gray-800 dark:text-gray-100"
                  }`}
                >
                  {isDeposit ? "+" : "-"}${formatCurrency(t.amount)}
                </span>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
